  setMagicError("");
  setMagicSuccess("");
  const emailErr = validateEmail(magicEmail);
  if (emailErr) { setMagicError(emailErr); return; }
  setMagicLoading(true);
  const result = await sendMagicLink(magicEmail);
  setMagicLoading(false);
  if (!result.ok) {
    setMagicError(result.error || "Failed to send magic link.");
    return;
  }
  setMagicSent(true);
  setMagicSuccess("Magic link and email code sent.");
};

const handleMagicVerify = async () => {
  setMagicError("");
  setMagicSuccess("");
  if (!magicCode.trim()) {
    setMagicError("Enter the code from your email.");
    return;
  }
  setMagicLoading(true);
  const result = await verifyEmailOtp(magicEmail, magicCode.trim());
  setMagicLoading(false);
  if (!result.ok || !result.session) {
    setMagicError(result.error || "Could not verify the email code.");
    return;
  }
  saveSession(result.session);
  router.push("/plan");
};

